<?php require_once __DIR__.'/../includes/functions.php';require_admin();require_role(['super_admin','admin','village_admin','content_admin']);if($_SERVER['REQUEST_METHOD']==='POST'){check_csrf();if(isset($_POST['delete_id'])){db()->prepare("DELETE FROM village_layout_items WHERE id=?")->execute([$_POST['delete_id']]);flash('success','Deleted');redirect('/admin/layout-builder.php');}db()->prepare("INSERT INTO village_layout_items(item_type,label,x_pos,y_pos,width,height,color,notes,zone,status,is_public,z_index) VALUES(?,?,?,?,?,?,?,?,?,?,?,?)")->execute([$_POST['item_type'],$_POST['label'],$_POST['x_pos'],$_POST['y_pos'],$_POST['width'],$_POST['height'],$_POST['color'],$_POST['notes'],$_POST['zone'],$_POST['status'],isset($_POST['is_public'])?1:0,$_POST['z_index']]);flash('success','Layout item added');redirect('/admin/layout-builder.php');}$items=db()->query("SELECT * FROM village_layout_items ORDER BY z_index,id")->fetchAll();include __DIR__.'/../includes/header.php';?><div class="admin"><?php include __DIR__.'/sidebar.php';?><main class="content"><h1>Business Village Layout Builder</h1><div class="layout"><form class="card" method="post"><input type="hidden" name="csrf" value="<?=csrf_token()?>"><label>Type<select name="item_type"><option>main_marquee</option><option>small_marquee</option><option>vehicle</option><option>food</option><option>entrance</option><option>exit</option><option>barrier</option><option>walkway</option><option>tree</option><option>stand</option><option>sponsor</option><option>investor</option></select></label><label>Label<input name="label" required></label><label>X<input name="x_pos" type="number" value="20"></label><label>Y<input name="y_pos" type="number" value="20"></label><label>Width<input name="width" type="number" value="140"></label><label>Height<input name="height" type="number" value="80"></label><label>Colour<input name="color"></label><label>Zone<input name="zone"></label><label>Status<input name="status" value="Available"></label><label>Z Index<input name="z_index" type="number" value="1"></label><label>Notes<textarea name="notes"></textarea></label><label><input type="checkbox" name="is_public" checked style="width:auto"> Public</label><button>Add Item</button></form><div class="canvas"><?php foreach($items as $it):?><div class="item <?=h($it['item_type'])?>" style="left:<?=h($it['x_pos'])?>px;top:<?=h($it['y_pos'])?>px;width:<?=h($it['width'])?>px;height:<?=h($it['height'])?>px;z-index:<?=h($it['z_index'])?>;<?= $it['color']?'background:'.h($it['color']).';':'' ?>">#<?=h($it['id'])?> <?=h($it['label'])?></div><?php endforeach;?></div></div><table><tr><th>ID</th><th>Label</th><th>Type</th><th>Delete</th></tr><?php foreach($items as $it):?><tr><td><?=h($it['id'])?></td><td><?=h($it['label'])?></td><td><?=h($it['item_type'])?></td><td><form method="post"><input type="hidden" name="csrf" value="<?=csrf_token()?>"><input type="hidden" name="delete_id" value="<?=h($it['id'])?>"><button>Delete</button></form></td></tr><?php endforeach;?></table></main></div><?php include __DIR__.'/../includes/footer.php';?>